#include <iostream>

// The function to be tested
int incrementPointerValue(int* ptr) {
    *ptr += 5;
    return *ptr;
}

int main() {
    std::cout << "Running test cases for Correct Version...\n";

    int score = 100;
    std::cout << "Initial score: " << score << std::endl;
    int newScore = incrementPointerValue(&score);
    std::cout << "Score after first increment: " << score << std::endl;
    std::cout << "Returned value from first call: " << newScore << std::endl;

    std::cout << "\n";

    int temperature = -5;
    std::cout << "Initial temperature: " << temperature << std::endl;
    int newTemperature = incrementPointerValue(&temperature);
    std::cout << "Temperature after increment: " << temperature << std::endl;
    std::cout << "Returned value from second call: " << newTemperature << std::endl;

    std::cout << "\n";

    int count = 0;
    std::cout << "Initial count: " << count << std::endl;
    int newCount = incrementPointerValue(&count);
    std::cout << "Count after increment: " << count << std::endl;
    std::cout << "Returned value from third call: " << newCount << std::endl;

    return 0;
}
